mapper.insert:
INSERT INTO article_view_daily (
    article_id, stat_date, view_count, unique_count
)
VALUES (
    #{articleId}, #{statDate}, #{viewDelta}, #{uniqueAbsolute}
)
ON DUPLICATE KEY UPDATE
    view_count = view_count + #{viewDelta},
    unique_count = GREATEST(unique_count, #{uniqueAbsolute})

mapper.update:
UPDATE article
SET view_count = view_count + #{delta}
WHERE id = #{articleId} AND deleted_at IS NULL
